import{_ as e,o as t,c as i,Q as a}from"./chunks/framework.9e8bdea8.js";const S=JSON.parse('{"title":"工程化","description":"","frontmatter":{},"headers":[],"relativePath":"js/engineering/index.md","filePath":"js/engineering/index.md"}'),s={name:"js/engineering/index.md"},c=a('<h1 id="工程化" tabindex="-1">工程化 <a class="header-anchor" href="#工程化" aria-label="Permalink to &quot;工程化&quot;">​</a></h1><p>JavaScript（JS）工程化是指通过使用各种工具、技术和最佳实践来提高 JavaScript 项目的开发效率、可维护性和可扩展性的过程。工程化涵盖了许多方面，包括构建工具（如 Webpack、Parcel）、模块化开发（如 ES6 模块、CommonJS）、代码规范（如 ESLint、Prettier）、自动化测试（如 Jest、Mocha）、持续集成和部署（CI/CD）、性能优化等。</p><p>通过工程化，开发团队可以更好地协作、管理项目依赖、自动化重复任务、确保代码质量和性能，并且更容易地维护和扩展项目。JavaScript 工程化已经成为现代前端开发的重要组成部分，帮助开发者更高效地构建复杂的 web 应用程序。</p><div class="tip custom-block"><p class="custom-block-title">知识体系</p><ul><li>构建工具: Vite、Webpack、Rollup</li><li>代码规范与质量保证：ESLint</li><li>自动化测试：Jest、Vitest</li><li>跨平台兼容： Babel</li></ul></div><div class="danger custom-block"><p class="custom-block-title">什么是自动化测试？</p><p>自动化测试，就是把我们平时对程序进行测试的操作，管理起来，不用每次都重复相同的测试操作。</p></div>',5),n=[c];function o(l,r,p,_,d,m){return t(),i("div",null,n)}const h=e(s,[["render",o]]);export{S as __pageData,h as default};
